    ClassParseResult ParseClasses(const std::filesystem::path& filePath)
    {
        ClassParseResult result;

        std::ifstream file(filePath);
        if (!file.is_open())
        {
            std::cerr << "Error: cannot open " << filePath << "\n";
            return result;
        }

        // Read all lines
        std::vector<std::string> lines;
        {
            std::string line;
            while (std::getline(file, line))
                lines.push_back(line);
        }

        // Pre-process: strip C and C++ comments from all lines.
        // This prevents commented-out declarations from being parsed as real functions.
        {
            bool in_block_comment = false;
            for (auto& line: lines)
            {
                std::string stripped_line;
                stripped_line.reserve(line.size());
                for (size_t i = 0; i < line.size(); ++i)
                {
                    if (in_block_comment)
                    {
                        if (line[i] == '*' && i + 1 < line.size() && line[i + 1] == '/')
                        {
                            in_block_comment = false;
                            ++i;  // skip '/'
                        }
                        // else: inside block comment, discard character
                    }
                    else
                    {
                        if (line[i] == '/' && i + 1 < line.size())
                        {
                            if (line[i + 1] == '/')
                            {
                                break;  // rest of line is a comment
                            }
                            else if (line[i + 1] == '*')
                            {
                                in_block_comment = true;
                                ++i;  // skip '*'
                                continue;
                            }
                        }
                        stripped_line += line[i];
                    }
                }
                line = std::move(stripped_line);
            }
        }
        // Phase 1: Build logical lines by joining continuations.
        // A logical line is complete when parentheses are balanced AND either:
        //   - It ends with ';'  (function declaration)
        //   - It's a standalone class definition (TClassDef/TClassDefExtend with no function)
        std::vector<std::string> logical_lines;
        std::string buffer;

        auto FlushBuffer = [&]()
        {
            if (!buffer.empty())
            {
                logical_lines.push_back(buffer);
                buffer.clear();
            }
        };

        for (auto& raw_line: lines)
        {
            std::string stripped = Trim(raw_line);

            // Skip preprocessor directives and empty lines
            if (stripped.empty())
            {
                // Empty line: flush any pending standalone class def
                if (!buffer.empty() && ParensBalanced(buffer))
                {
                    FlushBuffer();
                }
                continue;
            }
            if (stripped[0] == '#')
                continue;

            // Accumulate into buffer
            if (buffer.empty())
                buffer = stripped;
            else
                buffer += " " + stripped;

            // Check completeness
            if (ParensBalanced(buffer))
            {
                // Check if it ends with ';' (complete function declaration)
                if (buffer.back() == ';')
                {
                    FlushBuffer();
                }
                else if (IsStandaloneClassDef(buffer))
                {
                    // Standalone class definition — flush immediately
                    FlushBuffer();
                }
                // Otherwise, keep accumulating (next line may add function content)
            }
            // If parens unbalanced, keep accumulating
        }
        // Flush any remaining buffer
        FlushBuffer();

        // Phase 2: Process logical lines into ClassInfo structures.
        // Use indices into result.classes (not raw pointers) so that push_back-induced
        // reallocation never dangles our tracking variable.
        size_t current_class_idx = SIZE_MAX;  // sentinel — no current class yet
        size_t total_methods = 0;

        // Find an existing ClassInfo by name, or create one.  Returns its index.
        auto GetOrCreateClassIdx = [&](const std::string& name,
                                       const std::string& parent = "") -> size_t
        {
            for (size_t i = 0; i < result.classes.size(); ++i)
                if (result.classes[i].name == name)
                    return i;
            ClassInfo cls;
            cls.name = name;
            cls.parent = parent;
            result.classes.push_back(std::move(cls));
            return result.classes.size() - 1;
        };

        for (auto& ll: logical_lines)
        {
            std::string class_name, parent_name;
            size_t after_classdef = ExtractClassDef(ll, class_name, parent_name);

            if (after_classdef != std::string::npos)
            {
                // Found a class definition — start a new class (or re-open an existing one)
                current_class_idx = GetOrCreateClassIdx(class_name, parent_name);
                if (!parent_name.empty())
                {
                    result.classes[current_class_idx].parent = parent_name;
                    result.parent_map[class_name] = parent_name;
                }

                // Check for function declarations on the same line after the class def
                std::string remainder = Trim(ll.substr(after_classdef));
                if (!remainder.empty())
                {
                    if (remainder.back() == ';')
                    {
                        size_t pos = 0;
                        while (pos < remainder.size())
                        {
                            auto semi = remainder.find(';', pos);
                            if (semi == std::string::npos)
                                break;

                            std::string func_str = Trim(remainder.substr(pos, semi - pos + 1));
                            if (!func_str.empty())
                            {
                                FunctionDecl decl;
                                if (ParseFunctionDecl(func_str, class_name, decl))
                                {
                                    result.classes[current_class_idx].methods.push_back(
                                        std::move(decl));
                                    ++total_methods;
                                }
                                else
                                {
                                    std::cerr << "  Warning: unparsed function in class "
                                              << class_name << ": " << func_str << "\n";
                                }
                            }
                            pos = semi + 1;
                        }
                    }
                    else
                    {
                        std::cerr << "  Warning: incomplete function after class def " << class_name
                                  << ": " << remainder << "\n";
                    }
                }
            }
            else if (current_class_idx != SIZE_MAX)
            {
                // No class-def marker on this line — parse functions and route by prefix.
                // When a function's ClassName_ prefix differs from the current class, it means
                // that class has no TClassDef marker in the header.  Auto-create a ClassInfo
                // for it and make it current so subsequent methods land in the right place.
                size_t pos = 0;
                while (pos < ll.size())
                {
                    auto semi = ll.find(';', pos);
                    if (semi == std::string::npos)
                        break;

                    std::string func_str = Trim(ll.substr(pos, semi - pos + 1));
                    if (!func_str.empty())
                    {
                        FunctionDecl decl;
                        if (ParseFunctionDecl(func_str, result.classes[current_class_idx].name,
                                              decl))
                        {
                            if (decl.class_name.empty())
                            {
                                // Free function (e.g., expPROPSHEET_DEFAULT) embedded in a class
                                // section — not a class method; collect separately.
                                result.free_functions.push_back(std::move(decl));
                            }
                            else
                            {
                                // Route to the class that matches the function's own prefix.
                                size_t target_idx = current_class_idx;
                                if (decl.class_name != result.classes[current_class_idx].name)
                                {
                                    target_idx = GetOrCreateClassIdx(decl.class_name);
                                    current_class_idx = target_idx;
                                }
                                result.classes[target_idx].methods.push_back(std::move(decl));
                                ++total_methods;
                            }
                        }
                        else
                        {
                            std::cerr << "  Warning: unparsed function: " << func_str << "\n";
                        }
                    }
                    pos = semi + 1;
                }
            }
            else
            {
                // Function before any class def — shouldn't happen in kwx_classes.h
                std::cerr << "  Warning: function before any class definition: " << ll << "\n";
            }
        }

        // Phase 3: Resolve inheritance hierarchy flags.
        for (auto& cls: result.classes)
        {
            cls.is_window_derived = DerivesFrom(cls.name, "wxWindow", result.parent_map);
            cls.is_object_derived = DerivesFrom(cls.name, "wxObject", result.parent_map);
        }

        std::cerr << "  Classes:        " << result.classes.size() << "\n";
        std::cerr << "  Total methods:  " << total_methods << "\n";
        std::cerr << "  Class-section free funcs: " << result.free_functions.size() << "\n";

        return result;
    }

